'use strict';
const ntSanitizeHtml=(()=>{
const purifyConfig=Object.freeze({
ALLOWED_TAGS:['a','abbr','article','aside','b','blockquote','br','button','caption','cite','code','col','colgroup','dd','del','details','dfn','dialog','div','dl','dt','em','fieldset','figcaption','figure','footer','form','h1','h2','h3','h4','h5','h6','header','hgroup','hr','i','img','input','ins','kbd','label','legend','li','main','mark','meter','nav','ol','optgroup','option','output','p','picture','pre','progress','q','rp','rt','ruby','s','samp','search','section','select','small','source','span','strong','sub','summary','sup','table','tbody','td','textarea','tfoot','th','thead','time','tr','u','ul','var','wbr','data','menu','template','svg','g','defs','use','symbol','desc','circle','ellipse','line','polygon','polyline','rect','path','text','tspan','linearGradient','radialGradient','stop','clipPath','mask','pattern','filter','feGaussianBlur','feMerge','feMergeNode','feColorMatrix','feComposite','feFlood','feOffset',],
ALLOWED_ATTR:['class','id','href','src','srcset','alt','title','role','aria-hidden','aria-label','aria-labelledby','aria-describedby','aria-expanded','aria-controls','aria-live','aria-current','aria-pressed','aria-selected','aria-checked','aria-disabled','aria-busy','aria-haspopup','aria-modal','aria-required','aria-invalid','aria-orientation','aria-readonly','aria-multiline','aria-keyshortcuts','aria-valuenow','aria-valuemin','aria-valuemax','aria-valuetext','aria-sort','aria-level','aria-roledescription','aria-relevant','aria-multiselectable','aria-setsize','aria-posinset','type','name','value','placeholder','for','action','method','target','rel','width','height','loading','decoding','colspan','rowspan','scope','disabled','readonly','checked','selected','required','min','max','step','pattern','maxlength','minlength','tabindex','open','datetime','cite','enctype','novalidate','autocomplete','autofocus','multiple','accept','list','form','formaction','formmethod','formnovalidate','formenctype','formtarget','sizes','crossorigin','referrerpolicy','fetchpriority','inputmode','spellcheck','autocapitalize','enterkeyhint','lang','dir','translate','hidden','draggable','inert','popover','popovertarget','popovertargetaction','download','hreflang','ping','media','controls','autoplay','loop','muted','preload','poster','controlslist','playsinline','kind','srclang','default','reversed','start','wrap','cols','rows','low','high','optimum','usemap','label','viewBox','xmlns','fill','stroke','stroke-width','stroke-linecap','stroke-linejoin','stroke-dasharray','stroke-dashoffset','d','cx','cy','r','rx','ry','x','y','x1','y1','x2','y2','points','transform','preserveAspectRatio','fill-rule','clip-rule','opacity','fill-opacity','stroke-opacity','offset','stop-color','stop-opacity','gradientUnits',],
ALLOW_DATA_ATTR:true,
RETURN_TRUSTED_TYPE:false,
SANITIZE_DOM:false,});
const STRIP_NOISE=new Set(['body','html','head','title','meta']);
const reportStrip=(tags)=>{
try{
const blob=new Blob([JSON.stringify({
type:'dompurify-strip',
tags,
page:location.pathname,})],{type:'application/csp-report'});
navigator.sendBeacon('/csp-report',blob);}catch{}};
const sanitize=(input)=>{
const html=DOMPurify.sanitize(input,purifyConfig);
const alarmed=new Set();
for(const item of DOMPurify.removed){
const tag=item.element?.nodeName?.toLowerCase()
??item.attribute?.name?.toLowerCase();
if(tag&&!STRIP_NOISE.has(tag))alarmed.add(tag);}
if(alarmed.size>0)reportStrip([...alarmed]);
return html;};
if(window.trustedTypes?.createPolicy){
const policy=window.trustedTypes.createPolicy('nt-html',{
createHTML:sanitize,});
return(html)=>policy.createHTML(html);}
return sanitize;})();
const ntTrustedScript=(()=>{
const ALLOWED_ORIGINS=new Set([
location.origin,'https://js.stripe.com','https://challenges.cloudflare.com',]);
const validate=(input)=>{
if(input.startsWith('/')){
const resolved=new URL(input,location.origin).pathname;
if(resolved.startsWith('/assets/js/'))return input;
throw new TypeError(`Blocked script URL: ${input}`);}
try{
const url=new URL(input);
if(ALLOWED_ORIGINS.has(url.origin))return input;}catch{}
throw new TypeError(`Blocked script URL: ${input}`);};
if(window.trustedTypes?.createPolicy){
const policy=window.trustedTypes.createPolicy('nt-script-url',{
createScriptURL:validate,});
return(url)=>policy.createScriptURL(url);}
return validate;})();
if(window.trustedTypes?.createPolicy){
const SAFE_SCRIPT_ORIGINS=new Set([
location.origin,'https://js.stripe.com','https://challenges.cloudflare.com',]);
const beacon=(payload)=>{
try{
navigator.sendBeacon('/csp-report',
new Blob([JSON.stringify(payload)],{type:'application/csp-report'}),);}catch{}};
window.trustedTypes.createPolicy('default',{
createHTML:(input)=>{
beacon({type:'tt-default-fallback',sink:'createHTML',page:location.pathname});
return input;},
createScriptURL:(input)=>{
try{
if(SAFE_SCRIPT_ORIGINS.has(new URL(input,location.origin).origin)){
return input;}}catch{}
beacon({type:'tt-default-fallback',sink:'createScriptURL',url:input,page:location.pathname});
return input;},});}
const ntParseHtmlDocument=(()=>{
if(window.trustedTypes?.createPolicy){
const policy=window.trustedTypes.createPolicy('nt-dom-parser',{
createHTML:(input)=>input,});
return(text)=>new DOMParser().parseFromString(policy.createHTML(text),'text/html');}
return(text)=>new DOMParser().parseFromString(text,'text/html');})();
window.__ntSanitizeHtml=ntSanitizeHtml;
window.__ntTrustedScript=ntTrustedScript;
window.__ntParseHtmlDocument=ntParseHtmlDocument;